const items = $input.all();
const results = [];

// Blocked domains - emails from these are classified but never auto-replied
const BLOCKED_DOMAINS = [
  '@eftcorp.atlassian.net',
  '@noreply.github.com',
  '@notifications.google.com',
  '@mailer-daemon.',
  // n8n platform alerts (execution reports, workflow failures, billing)
  '@n8n.io',
  '@app.n8n.cloud',
  '@ianimmelman89.app.n8n.cloud'
];

// Subject patterns for n8n-generated reports/updates - no drafts needed
// Catches self-sent workflow reports even when 'from' is ian@anyvisionmedia.com
const N8N_REPORT_SUBJECT_PATTERNS = [
  /\bworkflow\s+execution/i,
  /\bexecution\s+(report|failed|error)/i,
  /\[n8n\]/i,
  /\bn8n\s+(alert|report|notification|update)/i,
  /\b(daily|weekly|monthly)\s+report\b/i,
  /\baudit\s+report\b/i,
  /\bbudget\s+enforcer/i,
  /\[ADS-\d+\]/i,
  /\[SHM\]/i,
  /\[ERR\]/i,
  /\[LI-\d+\]/i,
  /\bSHM\s+health\s+check/i,
  /\bworkflow\s+(update|summary)/i
];

for (const item of items) {
  const emailData = {
    from: item.json.from || item.json.sender || '',
    to: item.json.to || '',
    subject: item.json.subject || '',
    date: item.json.date || new Date().toISOString(),
    body: (item.json.textPlain || item.json.snippet || item.json.text || '').substring(0, 3000),
    hasAttachments: item.json.attachments ? item.json.attachments.length > 0 : false,
    attachmentCount: item.json.attachments ? item.json.attachments.length : 0,
    messageId: item.json.id || item.json.messageId || '',
    threadId: item.json.threadId || '',
    labelIds: item.json.labelIds || []
  };

  const fromLower = emailData.from.toLowerCase();
  // n8n-specific domains, split out so we can apply a dedicated `n8n` Gmail
  // label (and skip the AI call entirely). The broader BLOCKED_DOMAINS list
  // still gates auto-replies for non-n8n noise (github, eftcorp, etc.).
  const N8N_DOMAINS = [
    '@n8n.io',
    '@app.n8n.cloud',
    '@ianimmelman89.app.n8n.cloud'
  ];
  const isN8nDomain = N8N_DOMAINS.some(d => fromLower.includes(d));
  const isBlockedDomain = BLOCKED_DOMAINS.some(d => fromLower.includes(d));
  const isN8nReport = N8N_REPORT_SUBJECT_PATTERNS.some(rx => rx.test(emailData.subject || ''));
  // Either the message is from an n8n hostname, OR the subject pattern matches
  // a workflow report — in both cases we route to the dedicated n8n label
  // BEFORE the AI agent runs (saves tokens, gives clean Gmail filter view).
  const isN8nOrigin = isN8nDomain || isN8nReport;

  const classificationPrompt = `Analyze this business email. Return ONLY valid JSON, no markdown, no backticks.

From: ${emailData.from}
Subject: ${emailData.subject}
Date: ${emailData.date}
Body:
${emailData.body}
Has Attachments: ${emailData.hasAttachments ? 'Yes (' + emailData.attachmentCount + ')' : 'No'}

Return this exact JSON:
{
  "sender": "<email>",
  "sender_name": "<name>",
  "subject": "<subject>",
  "intent": "<what sender wants>",
  "tone": "<formal|informal|urgent|angry|friendly|neutral>",
  "urgency": "<high|medium|low>",
  "action_required": true or false,
  "department": "<ONE of: Accounting_Finance|Customer_Support|Sales|Management|Spam_Irrelevant>",
  "tags": ["<from: Invoice,Payment,Refund,Complaint,New_Lead,Contract,Meeting_Request,Follow_Up,Escalation,Urgent>"],
  "is_spam": true or false,
  "suggested_response": "<professional reply if action_required, else null>",
  "summary": "<1-2 sentence summary>",
  "escalation_needed": true or false,
  "is_interested_reply": true or false
}

Departments (pick exactly ONE — Admin, Legal, Internal, HR all fold into Management):
- Accounting_Finance: invoices, payments, billing, refunds, VAT/SARS, bank notices
- Customer_Support: complaints, technical issues, bug reports, account help, ticket follow-ups
- Sales: new enquiries, pricing, partnerships, lead generation, RFPs, demo requests
- Management: strategy, legal threats, contracts, NDAs, PR/media, escalations, admin/HR/internal, vendor setup
- Spam_Irrelevant: USE SPARINGLY — only when MULTIPLE clear spam signals are present (see below)

Spam rule (STRICT — defaults to NOT spam):
- Mark is_spam=true and department=Spam_Irrelevant ONLY when 2+ of these are true:
  * Sender domain is suspicious / spoofed / disposable
  * Body is generic mass-blast (no personalisation, no real signature)
  * Suspicious or shortened URLs / phishing indicators
  * Unsolicited promo with unrealistic claims ("guaranteed first page", "90% off")
- A personalised cold pitch from a real human/business → Sales (is_spam=false)
- A transactional email from a known SaaS (Stripe, QuickBooks, GitHub, Google) → the relevant real department, NOT spam
- When unsure between Spam_Irrelevant and a real department, choose the real department. False-spam is more costly than a misroute.

Urgency: HIGH only if action_required AND not spam AND (real client + urgent language, OR legal threat, OR payment dispute, OR escalated complaint, OR warm reply with deadline). Default medium.

Responses must be professional and concise.`;

  results.push({
    json: {
      ...emailData,
      classificationPrompt,
      is_n8n_domain: isN8nDomain,
      is_blocked_domain: isBlockedDomain,
      is_n8n_report: isN8nReport,
      is_n8n_origin: isN8nOrigin
    }
  });
}

return results;

const items = $input.all();
const results = [];

// Addresses n8n itself sends from — inbound messages from these are never
// auto-drafted (prevents reply-to-self loops when a workflow-sent email
// lands back in the inbox via Cc, auto-forward, or send-as alias).
const AUTOMATION_SENDERS = ["ian@anyvisionmedia.com", "noreply@anyvisionmedia.com", "noreply@n8n.io", "no-reply@n8n.io", "notifications@n8n.cloud"];

// Opt-out phrases (case-insensitive)
const OPT_OUT_PHRASES = [
  'unsubscribe', 'opt out', 'opt-out', 'remove me', 'stop emailing',
  'not interested', 'no thanks', 'no thank you', "i'll pass", 'take me off',
  'remove from list', 'stop sending', 'do not contact', "don't contact",
  'leave me alone', 'stop messaging', 'reported as spam', 'block sender',
  'cease and desist', 'gdpr removal', 'popia removal', 'remove my data'
];

// Ticket / reference number patterns
const TICKET_PATTERNS = [
  /\bTKT[-#]?\s*\d+/i,
  /\bTICKET\s*[#:]?\s*\d+/i,
  /\bTICKET\s+NUMBER\s*:?\s*\w+/i,
  /\bREF\s*[-:]\s*#?\s*[A-Z0-9]{3,}/i,
  /\bREFERENCE\s*(NUMBER|NO\.?|#)\s*:?\s*[A-Z0-9-]+/i,
  /\bENQ[-#]?\s*\d+/i,
  /\bENQUIRY\s*(NUMBER|NO\.?|#)\s*:?\s*\w+/i,
  /\bCASE\s*(ID|NUMBER|NO\.?|#)\s*:?\s*[A-Z0-9-]+/i,
  /\bINCIDENT\s*(ID|NUMBER|NO\.?|#)\s*:?\s*[A-Z0-9-]+/i,
  /\bSR[-#]\s*\d+/i,
  /\bINC[-#]\s*\d+/i,
  /\b[A-Z]{2,4}-\d{4,}\b/
];

const SIGNATURE = `<table cellpadding="0" cellspacing="0" border="0" style="font-family:'Segoe UI','Helvetica Neue',Arial,sans-serif;font-size:14px;line-height:1.4;color:#333333;"><tr><td style="vertical-align:top;padding-right:18px;"><a href="https://www.anyvisionmedia.com" target="_blank" style="text-decoration:none;"><img src="https://www.anyvisionmedia.com/logo-icon.png" alt="AnyVision Media" width="70" style="display:block;border:0;width:70px;height:70px;" /></a></td><td style="vertical-align:top;padding-left:18px;border-left:3px solid #6C63FF;"><table cellpadding="0" cellspacing="0" border="0"><tr><td style="font-size:20px;font-weight:700;color:#0A0F1C;padding-bottom:2px;letter-spacing:-0.3px;">Ian</td></tr><tr><td style="font-size:13px;font-weight:400;color:#6B7280;padding-bottom:10px;">Founder&nbsp;&nbsp;&#183;&nbsp;&nbsp;<span style="color:#6C63FF;font-weight:600;">AnyVision Media</span></td></tr><tr><td style="padding-bottom:10px;"><table cellpadding="0" cellspacing="0" border="0" width="200"><tr><td width="100" style="height:2px;background-color:#6C63FF;font-size:0;line-height:0;">&nbsp;</td><td width="100" style="height:2px;background-color:#00D4AA;font-size:0;line-height:0;">&nbsp;</td></tr></table></td></tr><tr><td style="font-size:12px;color:#333333;padding-bottom:3px;"><a href="mailto:ian@anyvisionmedia.com" style="color:#6C63FF;text-decoration:none;font-weight:500;">ian@anyvisionmedia.com</a></td></tr><tr><td style="font-size:12px;color:#333333;padding-bottom:3px;"><a href="https://www.anyvisionmedia.com" target="_blank" style="color:#6C63FF;text-decoration:none;font-weight:500;">www.anyvisionmedia.com</a></td></tr><tr><td style="font-size:11px;color:#9CA3AF;padding-top:2px;">Johannesburg, South Africa</td></tr></table></td></tr></table>`;

for (const item of items) {
  const emailData = $('Prepare Email Data').first().json;

  let parsed;
  let parsing_failed = false;
  try {
    let aiContent = item.json.output || '';
    if (!aiContent && item.json.choices) {
      aiContent = item.json.choices[0].message.content;
    }
    const cleaned = aiContent
      .replace(/```json\n?/g, '')
      .replace(/```\n?/g, '')
      .trim();
    parsed = JSON.parse(cleaned);
  } catch (e) {
    parsing_failed = true;
    // Route parse failures to Management (a real, wired department) so they
    // do not silently land in the General fallback and disappear.
    parsed = {
      sender: emailData.from || 'unknown',
      sender_name: 'Unknown',
      subject: emailData.subject || 'No Subject',
      intent: 'Classification failed - manual review required',
      tone: 'neutral',
      urgency: 'medium',
      action_required: true,
      department: 'Management',
      tags: ['Escalation'],
      is_spam: false,
      suggested_response: null,
      summary: 'Email could not be auto-classified. Manual review required.',
      escalation_needed: true,
      is_interested_reply: false
    };
  }

  // Reference number detection
  const subject = (emailData.subject || '').toUpperCase();
  const body = (emailData.body || '').substring(0, 2000).toUpperCase();
  const textToCheck = subject + ' ' + body;

  let has_reference_number = false;
  let matched_reference_pattern = '';
  for (const pattern of TICKET_PATTERNS) {
    const match = textToCheck.match(pattern);
    if (match) {
      has_reference_number = true;
      matched_reference_pattern = match[0];
      break;
    }
  }

  // Opt-out detection
  const bodyLower = (emailData.body || '').toLowerCase();
  const subjectLower = (emailData.subject || '').toLowerCase();
  const is_opt_out = OPT_OUT_PHRASES.some(phrase =>
    bodyLower.includes(phrase) || subjectLower.includes(phrase)
  );

  // Automation-sender detection — extract the bare email address from the
  // "From" header (which may be "Display Name <addr@host>") and check against
  // the AUTOMATION_SENDERS blocklist. Equality match on the bare address so a
  // legitimate client like iansomething@example.com is not blocked by a
  // substring check.
  const fromRaw = emailData.from || '';
  const bracketMatch = fromRaw.match(/<([^>]+)>/);
  const original_from_address = (bracketMatch ? bracketMatch[1] : fromRaw)
    .trim()
    .toLowerCase();
  const is_automation_sender = AUTOMATION_SENDERS.includes(original_from_address);

  // Build HTML response from suggested_response
  const html_response = (() => {
    const text = parsed.suggested_response || '';
    if (!text) return '';
    const paragraphs = text.split(/\n\n+/);
    const htmlParagraphs = paragraphs
      .map(p => p.replace(/\n/g, '<br>'))
      .map(p => '<p style="margin:0 0 12px 0;font-family:Segoe UI,Helvetica Neue,Arial,' +
        'sans-serif;font-size:14px;line-height:1.5;color:#333333;">' + p + '</p>')
      .join('');
    return '<div style="font-family:Segoe UI,Helvetica Neue,Arial,sans-serif;">' +
      htmlParagraphs + '<br>' + SIGNATURE + '</div>';
  })();

  results.push({
    json: {
      original_from: emailData.from || '',
      original_to: emailData.to || '',
      original_subject: emailData.subject || '',
      original_date: emailData.date || '',
      original_body: emailData.body || '',
      original_message_id: emailData.messageId || '',
      original_thread_id: emailData.threadId || '',
      has_original_attachments: emailData.hasAttachments || false,
      sender: parsed.sender || emailData.from || '',
      sender_name: parsed.sender_name || 'Unknown',
      subject: parsed.subject || emailData.subject || '',
      intent: parsed.intent || '',
      tone: parsed.tone || 'neutral',
      urgency: parsed.urgency || 'medium',
      action_required: parsed.action_required || false,
      department: parsed.department || 'Management',
      tags: parsed.tags || [],
      tags_string: (parsed.tags || []).join(', '),
      is_spam: parsed.is_spam || false,
      parsing_failed,
      suggested_response: parsed.suggested_response || '',
      html_response,
      summary: parsed.summary || '',
      escalation_needed: parsed.escalation_needed || false,
      is_interested_reply: parsed.is_interested_reply || false,
      has_reference_number,
      matched_reference_pattern,
      is_opt_out,
      original_from_address,
      is_automation_sender,
      is_blocked_domain: emailData.is_blocked_domain || false,
      is_n8n_report: emailData.is_n8n_report || false,
      processed_at: new Date().toISOString(),
      ticket_number: 'TKT-' + Date.now()
    }
  });
}

return results;

const items = $input.all();

// Mirror of the Switch "Route by Department" rules. Anything not in this
// map falls through to the General label (Label_5) — matches the workflow's
// fallbackOutput behaviour.
const DEPT_TO_LABEL = {
  'Spam_Irrelevant': 'Junk',
  'Accounting_Finance': 'Finance',
  'Customer_Support': 'Support',
  'Sales': 'Sales',
  'Management': 'Management'
};

return items.map(item => {
  const d = item.json;
  const applied_dept_label = DEPT_TO_LABEL[d.department] || 'General';
  // Same gate as the "Is Urgent?" If node. Keep these two in sync.
  const urgent_label_applied = (
    d.urgency === 'high' &&
    d.is_spam === false &&
    d.action_required === true
  );
  return {
    json: {
      ...d,
      applied_dept_label,
      urgent_label_applied
    }
  };
});

const item = $input.first();
const d = item.json;

if (d.department === 'Sales' && d.tags_string && d.tags_string.includes('New_Lead')) {
  return [{
    json: {
      date: d.processed_at,
      lead_name: d.sender_name,
      email: d.sender,
      subject: d.original_subject,
      interest: d.intent,
      summary: d.summary,
      urgency: d.urgency,
      status: 'New',
      follow_up_date: new Date(Date.now() + 2 * 24 * 60 * 60 * 1000)
        .toISOString().split('T')[0],
      is_lead: true
    }
  }];
}

return [{ json: { is_lead: false } }];

